module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const label = esc((args.label || 'Proof').trim());
const qedRaw = (args.qed != null) ? String(args.qed) : '□';
const qedTrim = qedRaw.trim();
const accent = (args.accent && String(args.accent).trim()) || 'inherit';
const qedColor = (args.accent && String(args.accent).trim()) || 'currentColor';
const fontsize = (args.fontsize && String(args.fontsize).trim()) || 'inherit';
const border = String(args.border) === 'true';
const cls = 'mdp-mod-proof' + (border ? ' mdp-pf-bordered' : '');
const body = (content || '').trim();
// The default QED mark is a HOLLOW square drawn with a border (font-independent —
// the bare □ glyph renders filled/as tofu in many fonts). A custom qed is text.
const qedSpan = !qedTrim ? '' :
  (qedTrim === '□' || qedTrim === '\\square')
    ? `<span class="mdp-pf-qed" style="width:0.62em;height:0.62em;border:1.6px solid ${qedColor};box-sizing:border-box;margin-top:0.34em;"></span>`
    : `<span class="mdp-pf-qed">${esc(qedTrim)}</span>`;
return `\n\n<div class="${cls}" style="--pf-accent:${accent}; --pf-size:${fontsize};"><span class="mdp-pf-lead">${label}.</span> <div class="mdp-pf-body">\n\n${body}\n\n</div>${qedSpan}</div>\n\n`;
